  1→import type { ChannelPlugin, ClawdbotConfig } from "clawdbot/plugin-sdk";
  2→import { DEFAULT_ACCOUNT_ID, PAIRING_APPROVED_MESSAGE } from "clawdbot/plugin-sdk";
  3→import type { ResolvedFeishuAccount, FeishuConfig } from "./types.js";
  4→import { resolveFeishuAccount, resolveFeishuCredentials } from "./accounts.js";
  5→import { feishuOutbound } from "./outbound.js";
  6→import { probeFeishu } from "./probe.js";
  7→import { resolveFeishuGroupToolPolicy } from "./policy.js";
  8→import { normalizeFeishuTarget, looksLikeFeishuId, formatFeishuTarget } from "./targets.js";
  9→import { sendMessageFeishu } from "./send.js";
 10→import {
 11→  listFeishuDirectoryPeers,
 12→  listFeishuDirectoryGroups,
 13→  listFeishuDirectoryPeersLive,
 14→  listFeishuDirectoryGroupsLive,
 15→} from "./directory.js";
 16→import { feishuOnboardingAdapter } from "./onboarding.js";
 17→
 18→const meta = {
 19→  id: "feishu",
 20→  label: "Feishu",
 21→  selectionLabel: "Feishu/Lark (飞书)",
 22→  docsPath: "/channels/feishu",
 23→  docsLabel: "feishu",
 24→  blurb: "飞书/Lark enterprise messaging.",
 25→  aliases: ["lark"],
 26→  order: 70,
 27→} as const;
 28→
 29→export const feishuPlugin: ChannelPlugin<ResolvedFeishuAccount> = {
 30→  id: "feishu",
 31→  meta: {
 32→    ...meta,
 33→  },
 34→  pairing: {
 35→    idLabel: "feishuUserId",
 36→    normalizeAllowEntry: (entry) => entry.replace(/^(feishu|user|open_id):/i, ""),
 37→    notifyApproval: async ({ cfg, id }) => {
 38→      await sendMessageFeishu({
 39→        cfg,
 40→        to: id,
 41→        text: PAIRING_APPROVED_MESSAGE,
 42→      });
 43→    },
 44→  },
 45→  capabilities: {
 46→    chatTypes: ["direct", "channel"],
 47→    polls: false,
 48→    threads: true,
 49→    media: true,
 50→    reactions: true,
 51→    edit: true,
 52→    reply: true,
 53→  },
 54→  agentPrompt: {
 55→    messageToolHints: () => [
 56→      "- Feishu targeting: omit `target` to reply to the current conversation (auto-inferred). Explicit targets: `user:open_id` or `chat:chat_id`.",
 57→      "- Feishu supports interactive cards for rich messages.",
 58→    ],
 59→  },
 60→  groups: {
 61→    resolveToolPolicy: resolveFeishuGroupToolPolicy,
 62→  },
 63→  reload: { configPrefixes: ["channels.feishu"] },
 64→  configSchema: {
 65→    schema: {
 66→      type: "object",
 67→      additionalProperties: false,
 68→      properties: {
 69→        enabled: { type: "boolean" },
 70→        appId: { type: "string" },
 71→        appSecret: { type: "string" },
 72→        encryptKey: { type: "string" },
 73→        verificationToken: { type: "string" },
 74→        domain: { type: "string", enum: ["feishu", "lark"] },
 75→        connectionMode: { type: "string", enum: ["websocket", "webhook"] },
 76→        webhookPath: { type: "string" },
 77→        webhookPort: { type: "integer", minimum: 1 },
 78→        dmPolicy: { type: "string", enum: ["open", "pairing", "allowlist"] },
 79→        allowFrom: { type: "array", items: { oneOf: [{ type: "string" }, { type: "number" }] } },
 80→        groupPolicy: { type: "string", enum: ["open", "allowlist", "disabled"] },
 81→        groupAllowFrom: { type: "array", items: { oneOf: [{ type: "string" }, { type: "number" }] } },
 82→        requireMention: { type: "boolean" },
 83→        historyLimit: { type: "integer", minimum: 0 },
 84→        dmHistoryLimit: { type: "integer", minimum: 0 },
 85→        textChunkLimit: { type: "integer", minimum: 1 },
 86→        chunkMode: { type: "string", enum: ["length", "newline"] },
 87→        mediaMaxMb: { type: "number", minimum: 0 },
 88→        renderMode: { type: "string", enum: ["auto", "raw", "card"] },
 89→      },
 90→    },
 91→  },
 92→  config: {
 93→    listAccountIds: () => [DEFAULT_ACCOUNT_ID],
 94→    resolveAccount: (cfg) => resolveFeishuAccount({ cfg }),
 95→    defaultAccountId: () => DEFAULT_ACCOUNT_ID,
 96→    setAccountEnabled: ({ cfg, enabled }) => ({
 97→      ...cfg,
 98→      channels: {
 99→        ...cfg.channels,
100→        feishu: {
101→          ...cfg.channels?.feishu,
102→          enabled,
103→        },
104→      },
105→    }),
106→    deleteAccount: ({ cfg }) => {
107→      const next = { ...cfg } as ClawdbotConfig;
108→      const nextChannels = { ...cfg.channels };
109→      delete (nextChannels as Record<string, unknown>).feishu;
110→      if (Object.keys(nextChannels).length > 0) {
111→        next.channels = nextChannels;
112→      } else {
113→        delete next.channels;
114→      }
115→      return next;
116→    },
117→    isConfigured: (_account, cfg) =>
118→      Boolean(resolveFeishuCredentials(cfg.channels?.feishu as FeishuConfig | undefined)),
119→    describeAccount: (account) => ({
120→      accountId: account.accountId,
121→      enabled: account.enabled,
122→      configured: account.configured,
123→    }),
124→    resolveAllowFrom: ({ cfg }) =>
125→      (cfg.channels?.feishu as FeishuConfig | undefined)?.allowFrom ?? [],
126→    formatAllowFrom: ({ allowFrom }) =>
127→      allowFrom
128→        .map((entry) => String(entry).trim())
129→        .filter(Boolean)
130→        .map((entry) => entry.toLowerCase()),
131→  },
132→  security: {
133→    collectWarnings: ({ cfg }) => {
134→      const feishuCfg = cfg.channels?.feishu as FeishuConfig | undefined;
